def closest_to_zero(nums: list[int]) -> tuple[int, int]:
    nums.sort()
    left, right = 0, len(nums) - 1
    min_sum = float('inf')
    closest_pair = ()
    while left < right:
        current_sum = nums[left] + nums[right]
        if abs(current_sum) < abs(min_sum):
            min_sum = current_sum
            closest_pair = (nums[left], nums[right])
        if current_sum < 0:
            left += 1
        elif current_sum > 0:
            right -= 1
        else:
            break
    return closest_pair
